import { Component, OnInit } from "@angular/core";
import { DatePipe, formatNumber } from "@angular/common";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators,
} from "@angular/forms";
import { CalcMethod } from "src/app/views/Models/Loan/CalcMethod";
import { HttpClient } from "@angular/common/http";
import { EnvService } from "src/app/core/services/env.service";
import { AlertService } from "src/app/core/services/alert.service";
import { Education } from "src/app/views/Models/Settings/Education";
import { ReferencesService } from "src/app/core/services/references.service";
import { IEduLevel } from "src/app/views/Models/References/EduLevel";
import { StaticRef } from "src/app/views/Models/References/StaticRef";

@Component({
  selector: "app-headoffice-edu-qual",
  templateUrl: "./headoffice-edu-qual.page.html",
  styleUrls: ["./headoffice-edu-qual.page.scss"],
})
export class HeadofficeEduQualPage implements OnInit {
  [x: string]: any;
  eduLevelForm: any;
  levelFraTypes: StaticRef[];
  EduLevelForm: FormGroup = this.formBuilder.group({
    edu_level_code: [""],
    edu_level_name: ["", [Validators.required]],
    active_rec: [0],
    ref_code: ["", [Validators.required]],
  });
  noWhitespaceValidator(control: FormControl) {
    const isWhitespace =
      control.value !== null &&
      (control.value || "").toString().trim().length === 0;
    const isValid = !isWhitespace;
    return isValid ? null : { whitespace: true };
  }
  constructor(
    private formBuilder: FormBuilder,
    private datepipe: DatePipe,
    private http: HttpClient,
    private env: EnvService,
    private alertServices: AlertService,
    private ReferencesService: ReferencesService
  ) {}
  showLoader: boolean = false;
  eduLevel: IEduLevel[];
  isSubmitted: boolean = false;
  isInserting: boolean = false;
  isUpdating: boolean = false;

  ngOnInit() {
    this.loadEdu();
  }
  async loadEdu() {
    this.eduLevel = await this.ReferencesService.getAllEduLevel();
    this.levelFraTypes = await this.ReferencesService.GetAllEduLevelFra();
  }
  updateEdu(index: number) {
    const eduLevel = this.eduLevel[index];
    this.EduLevelForm.patchValue({
      edu_level_code: eduLevel.edu_level_code,
      edu_level_name: eduLevel.edu_level_name,
      active_rec: eduLevel.active_rec == "1",
      ref_code: Number(eduLevel.edu_level_code_fra),
    });
    this.isInserting = false;
    this.isUpdating = true;
  }
  async insertEduLevel() {
    this.isUpdating = false;
    this.isInserting = true;
  }
  async deleteEdu(edu_level_code: string) {
    if (await this.alertServices.SaveAlert("هل تريد الحذف؟"))
      this.ReferencesService.GetEduLevelsDelete(edu_level_code.toString()).then(
        () => {
          this.alertServices.showAlertConfirm("تم الحذف بنجاح", true);
        }
      );
  }
  EduFra() {
    if (this.EduLevelForm.value.calc_method == "4") {
      this.EduLevelForm.get("apply_rounding").setValue(0);
      this.isDecreasingCalcMethod = true;
    } else {
      this.isDecreasingCalcMethod = false;
    }
  }
  clearForms() {
    this.isInserting = false;
    this.isUpdating = false;
    this.isSubmitted = false;
    this.EduLevelForm.reset();
  }
  async submitEduInsert() {
    try {
      if (this.EduLevelForm.valid) {
        if (await this.alertServices.SaveAlert("هل تريد الاضافة؟"))
          this.ReferencesService.GetEduLevelsInsert(
            this.EduLevelForm.value.edu_level_name,
            this.EduLevelForm.value.active_rec === true ? 1 : 0,
            this.EduLevelForm.value.ref_code
          ).then(() => {
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          });
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
  async submitEduUpdate() {
    try {
      if (this.EduLevelForm.valid) {
        if (await this.alertServices.SaveAlert("هل تريد تعديل البيانات؟"))
          this.ReferencesService.GetEduLevelsUpdate(
            Number(this.EduLevelForm.value.edu_level_code),
            this.EduLevelForm.value.edu_level_name,
            this.EduLevelForm.value.active_rec === true ? 1 : 0,
            this.EduLevelForm.value.ref_code
          ).then(() => {
            this.alertServices.showAlertConfirm("تم الحفظ بنجاح", true);
          });
      } else {
        this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
      }
    } catch {}
  }
}
